export const getWorkflowComparativeResponseRankedWorkflowsItemProjectedComplexityMax = 100;

export const getWorkflowComparativeResponseRankedWorkflowsItemHotspotCountMin = 0;

export const getWorkflowComparativeResponseHotspotConcentrationConcentrationRatioMin = 0;
export const getWorkflowComparativeResponseHotspotConcentrationConcentrationRatioMax = 1;

export const getWorkflowComparativeResponseHotspotConcentrationTopRiskScoreMin = 0;
export const getWorkflowComparativeResponseHotspotConcentrationTopRiskScoreMax = 100;

